class MinStack:

    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        min_val = min(val, self.min_stack[-1] if self.min_stack else val)
        self.min_stack.append(min_val)

    def pop(self) -> None:
        self.stack.pop()
        self.min_stack.pop()

    def top(self) -> int:
        return self.stack[-1]

    def getMin(self) -> int:
        return self.min_stack[-1]

def minStack(operations, arguments):
    obj = MinStack()
    results = []
    for op, args in zip(operations[1:], arguments[1:]):
        if op == 'push':
            obj.push(args[0])
        elif op == 'pop':
            obj.pop()
        elif op == 'top':
            results.append(obj.top())
        elif op == 'getMin':
            results.append(obj.getMin())
    return results

